const inputItems = $input.all();

const websiteKeys = [
  'Веб-сайт 1', 'Веб-сайт 2', 'Веб-сайт 3', 'Веб-сайт',
  'Сайт 1', 'Сайт 2', 'Сайт 3', 'Сайт',
  'Website 1', 'Website 2', 'Website 3', 'Website',
  'Site 1', 'Site 2', 'Site 3', 'Site',
  'URL', 'Url', 'url', 'Домен', 'Domain',
  'Главная страница', 'Homepage'
];

const vkKeys = [
  'ВКонтакте', 'Вконтакте', 'VK', 'vk', 'VK URL', 'vk_url',
  'ВК', 'Группа ВК', 'Сообщество', 'Community'
];

const telegramKeys = [
  'Telegram 1', 'Telegram 2', 'Telegram 3',
  'Telegram', 'telegram', 'Телеграм', 'Telegram URL', 'telegram_url',
  'Канал', 'TG', 'tg', 'Telegram канал', 'Канал Telegram'
];

const otherUrlKeys = [
  '2GIS URL', '2ГИС', '2gis', 'Yandex URL', 'Я.Карты', 'Яндекс.Карты',
  'Карта', 'Map URL', 'Instagram', 'instagram', 'Facebook', 'facebook',
  'Twitter', 'twitter', 'YouTube', 'youtube', 'Youtube',
  'WhatsApp 1', 'WhatsApp 2', 'WhatsApp 3', 'WhatsApp', 'Viber'
];

const preferredKeys = [...websiteKeys, ...vkKeys, ...telegramKeys, ...otherUrlKeys];

const hintKeyRegex = /(сайт|веб|website|site|url|домен|вконтакте|\bвк\b|\bvk\b|telegram|телеграм|канал|t\.me|instagram|инстаграм|facebook|2gis|2гис|yandex|яндекс|карт)/i;

const vkHostRegex = /^(?:www\.|m\.)?vk\.(?:com|ru)$/i;
const telegramHostRegex = /^(?:www\.)?(?:t\.me|telegram\.me|telegram\.org)$/i;
const blockedSocialHostRegex = /^(?:www\.)?(?:facebook\.com|instagram\.com|linkedin\.com|twitter\.com|x\.com|youtube\.com|youtu\.be|tiktok\.com|ok\.ru|pinterest\.com|threads\.net|2gis\.ru|2gis\.com|2gis\.kz|yandex\.ru|maps\.yandex\.ru|google\.com|maps\.google\.com|wa\.me|whatsapp\.com|api\.whatsapp\.com|chat\.whatsapp\.com|viber\.com|viber\.click|max\.ru|max\.me)$/i;

const seedBlockedHostRegex = /^(?:www\.)?(?:wa\.me|whatsapp\.com|api\.whatsapp\.com|chat\.whatsapp\.com|viber\.com|viber\.click|max\.ru|max\.me|youtu\.be|youtube\.com|twitter\.com|x\.com|tiktok\.com|pinterest\.com|threads\.net)$/i;
const allSocialHostRegex = /^(?:www\.|m\.)?(?:vk\.com|vk\.ru|t\.me|telegram\.me|telegram\.org|facebook\.com|instagram\.com|linkedin\.com|twitter\.com|x\.com|youtube\.com|tiktok\.com|ok\.ru)$/i;

const deepPaths = [
  '/contacts', '/contact', '/kontakty',
  '/о-нас', '/o-nas', '/o-kompanii', '/about',
  '/contact-us', '/about-us',
  '/контакты', '/связаться',
  '/info', '/feedback', '/team', '/команда'
];

const maxSeedUrlsPerRow = 3;
const maxCrawlUrlsPerRow = 8;
const maxValueLength = 5000;

const clean = (value) => {
  const s = String(value ?? '').trim();
  return s.length > maxValueLength ? s.slice(0, maxValueLength) : s;
};

const trimToken = (value) =>
  clean(value).replace(/^[\s"'<>()[\]{}]+|[\s"'<>()[\]{}.,;:!]+$/g, '');

const looksLikeEmail = (value) =>
  /^[a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,24}$/i.test(String(value || '').trim());

const normalizeUrl = (value) => {
  let normalized = trimToken(value);
  if (!normalized) return '';

  if (/^[+\d\s().-]{6,}$/.test(normalized)) return '';
  if (/^\d+([.,]\d+)?$/.test(normalized)) return '';
  if (!/[a-zа-яё]/i.test(normalized)) return '';
  if (looksLikeEmail(normalized)) return '';

  if (!/^https?:\/\//i.test(normalized)) {
    normalized = 'https://' + normalized.replace(/^\/+/, '');
  }

  try {
    const parsed = new URL(normalized);
    const host = parsed.hostname;
    if (!host || !host.includes('.')) return '';
    if (!/[a-z]/i.test(host)) return '';
    if (host.length < 4) return '';
    if (parsed.username || parsed.password) return '';
    if (seedBlockedHostRegex.test(host)) return '';
    parsed.hash = '';
    return parsed.toString();
  } catch {
    return '';
  }
};

const canonicalUrlKey = (url) => {
  try {
    const parsed = new URL(url);
    const host = parsed.hostname.toLowerCase().replace(/^www\./, '');
    const pathname = parsed.pathname.replace(/\/+$/g, '') || '/';
    const search = parsed.search || '';
    return host + pathname + search;
  } catch {
    return String(url || '').toLowerCase();
  }
};

const extractUrlTokens = (value) => {
  const raw = clean(value);
  if (!raw) return [];

  const sanitized = raw.replace(/[a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,24}/gi, ' ');

  const tokens = new Set();

  const splitParts = sanitized
    .split(/[\n,;|]+/)
    .map(trimToken)
    .filter(Boolean);

  for (const part of splitParts) {
    const normalized = normalizeUrl(part);
    if (normalized) tokens.add(normalized);
  }

  const directMatches = sanitized.match(/https?:\/\/[^\s"'<>]+/gi) || [];
  for (const match of directMatches) {
    const normalized = normalizeUrl(match);
    if (normalized) tokens.add(normalized);
  }

  const domainMatches = sanitized.match(/(?:[a-z0-9-]+\.)+[a-z]{2,}(?:\/[^\s"'<>]*)?/gi) || [];
  for (const match of domainMatches) {
    const normalized = normalizeUrl(match);
    if (normalized) tokens.add(normalized);
  }

  return Array.from(tokens);
};


const extract2gisFirmId = (url) => {
  try {
    const parsed = new URL(url);
    const host = parsed.hostname.toLowerCase();
    if (!/(^|\.)2gis\.(ru|com|kz)$/.test(host)) return '';
    const m = parsed.pathname.match(/\/firm\/([0-9]{6,})/i);
    return m ? m[1] : '';
  } catch {
    return '';
  }
};

const buildDeepEntries = (seedUrl) => {
  const deepEntries = [];

  let parsed;
  try {
    parsed = new URL(seedUrl);
  } catch {
    return deepEntries;
  }

  const host = parsed.hostname.toLowerCase();

  if (vkHostRegex.test(host)) {
    const slug = parsed.pathname.replace(/^\/+|\/+$/g, '');
    if (slug) {
      const mobileUrl = normalizeUrl('https://m.vk.com/' + slug);
      if (mobileUrl) {
        deepEntries.push({ url: mobileUrl, depth: 1, source: 'vk-mobile' });
      }
      const desktopUrl = normalizeUrl('https://vk.com/' + slug);
      if (desktopUrl && canonicalUrlKey(desktopUrl) !== canonicalUrlKey(seedUrl)) {
        deepEntries.push({ url: desktopUrl, depth: 1, source: 'vk-desktop' });
      }
    }
    return deepEntries;
  }

  if (telegramHostRegex.test(host)) {
    const slug = parsed.pathname.replace(/^\/+|\/+$/g, '').split('/')[0];
    if (slug && slug !== 's' && !slug.startsWith('joinchat') && !slug.startsWith('+')) {
      const previewUrl = normalizeUrl('https://t.me/s/' + slug);
      if (previewUrl) {
        deepEntries.push({ url: previewUrl, depth: 1, source: 'telegram-preview' });
      }
      const directUrl = normalizeUrl('https://t.me/' + slug);
      if (directUrl && canonicalUrlKey(directUrl) !== canonicalUrlKey(seedUrl)) {
        deepEntries.push({ url: directUrl, depth: 1, source: 'telegram-direct' });
      }
    }
    return deepEntries;
  }

  if (blockedSocialHostRegex.test(host)) {
    return deepEntries;
  }

  const origin = parsed.origin;
  for (const path of deepPaths) {
    const deepUrl = normalizeUrl(origin + path);
    if (deepUrl) {
      deepEntries.push({ url: deepUrl, depth: 1, source: 'deep:' + path });
    }
  }

  return deepEntries;
};

const outputItems = [];

inputItems.forEach((item, sourceIndex) => {
  try {
  const row = item.json || {};
  const dgisApiKey = [row['2GIS API Key'], row['2gis_api_key'], row['dgis_api_key'], row['catalog_api_key']].map((v)=>String(v||'').trim()).find(Boolean) || '';
  const seedCanonicalSet = new Set();
  const seedCandidates = [];

  const pushSeed = (url, sourceTag) => {
    if (!url || seedCandidates.length >= maxSeedUrlsPerRow) return;

    const key = canonicalUrlKey(url);
    if (!key || seedCanonicalSet.has(key)) return;

    seedCanonicalSet.add(key);
    seedCandidates.push({ url, sourceTag });
  };

  const expandHandles = (key, rawValue) => {
    const text = clean(rawValue);
    if (!text) return [];

    const isVkKey = vkKeys.includes(key);
    const isTelegramKey = telegramKeys.includes(key);
    if (!isVkKey && !isTelegramKey) return [];

    const out = [];
    const tokens = text.split(/[\s,;|]+/).map((t) => t.trim()).filter(Boolean);

    for (const token of tokens) {
      const handle = token.replace(/^@+/, '').replace(/^https?:\/\//i, '').replace(/[^a-zA-Z0-9_./-]/g, '');
      if (!handle || handle.length < 3 || handle.length > 64) continue;
      if (/\./.test(handle) && /^[a-z0-9-]+\.[a-z]{2,}/i.test(handle)) continue;
      const slug = handle.split('/').filter(Boolean)[0];
      if (!slug) continue;

      if (isTelegramKey) {
        const url = normalizeUrl('https://t.me/' + slug);
        if (url) out.push(url);
      }
      if (isVkKey) {
        const url = normalizeUrl('https://vk.com/' + slug);
        if (url) out.push(url);
      }
    }

    return out;
  };

  for (const key of preferredKeys) {
    if (seedCandidates.length >= maxSeedUrlsPerRow) break;
    if (!Object.prototype.hasOwnProperty.call(row, key)) continue;

    const urls = extractUrlTokens(row[key]);
    for (const url of urls) {
      pushSeed(url, 'key:' + key);
      if (seedCandidates.length >= maxSeedUrlsPerRow) break;
    }

    const handleUrls = expandHandles(key, row[key]);
    for (const url of handleUrls) {
      pushSeed(url, 'handle:' + key);
      if (seedCandidates.length >= maxSeedUrlsPerRow) break;
    }
  }

  if (seedCandidates.length < maxSeedUrlsPerRow) {
    for (const [key, value] of Object.entries(row)) {
      if (seedCandidates.length >= maxSeedUrlsPerRow) break;
      if (!hintKeyRegex.test(key)) continue;

      const urls = extractUrlTokens(value);
      for (const url of urls) {
        pushSeed(url, 'hint:' + key);
        if (seedCandidates.length >= maxSeedUrlsPerRow) break;
      }
    }
  }

  if (seedCandidates.length < maxSeedUrlsPerRow) {
    for (const value of Object.values(row)) {
      if (seedCandidates.length >= maxSeedUrlsPerRow) break;

      const urls = extractUrlTokens(value);
      for (const url of urls) {
        pushSeed(url, 'any-value');
        if (seedCandidates.length >= maxSeedUrlsPerRow) break;
      }
    }
  }

  const crawlSet = new Set();
  const crawlEntries = [];

  const pushCrawl = (entry, seed, seedIndex) => {
    if (!entry?.url || crawlEntries.length >= maxCrawlUrlsPerRow) return;

    const key = canonicalUrlKey(entry.url);
    if (!key || crawlSet.has(key)) return;

    crawlSet.add(key);

    let targetHost = '';
    let isSocial = false;
    try {
      const parsed = new URL(entry.url);
      targetHost = parsed.hostname.replace(/^www\./i, '').toLowerCase();
      isSocial = allSocialHostRegex.test(parsed.hostname);
    } catch {
      targetHost = '';
    }

    crawlEntries.push({
      json: {
        ...row,
        targetUrl: entry.url,
        targetHost,
        targetIsSocial: isSocial,
        seed_url: seed.url,
        seed_source: seed.sourceTag,
        crawl_depth: entry.depth,
        url_source: entry.depth === 0 ? seed.sourceTag : entry.source,
        url_detected: true,
        source_row_index: sourceIndex,
        source_row_number: row.row_number ?? '',
        source_url_rank: seedIndex + 1,
        source_urls_count: seedCandidates.length,
        dgis_api_key_present: Boolean(dgisApiKey),
      },
      pairedItem: { item: sourceIndex },
    });
  };

  const deepPerSeed = [];

  for (let seedIndex = 0; seedIndex < seedCandidates.length; seedIndex++) {
    const seed = seedCandidates[seedIndex];
    pushCrawl({ url: seed.url, depth: 0, source: 'seed' }, seed, seedIndex);
    const firmId = extract2gisFirmId(seed.url);
    if (firmId && dgisApiKey) {
      const apiUrl = normalizeUrl(`https://catalog.api.2gis.com/3.0/items/byid?id=${firmId}&fields=items.contact_groups&key=${encodeURIComponent(dgisApiKey)}`);
      if (apiUrl) pushCrawl({ url: apiUrl, depth: 0, source: '2gis-api' }, seed, seedIndex);
    }
    deepPerSeed[seedIndex] = buildDeepEntries(seed.url);
  }

  let deepCursor = 0;
  let addedAny = true;

  while (crawlEntries.length < maxCrawlUrlsPerRow && addedAny) {
    addedAny = false;

    for (let seedIndex = 0; seedIndex < seedCandidates.length; seedIndex++) {
      if (crawlEntries.length >= maxCrawlUrlsPerRow) break;

      const deepList = deepPerSeed[seedIndex] || [];
      const deepEntry = deepList[deepCursor];
      if (!deepEntry) continue;

      pushCrawl(deepEntry, seedCandidates[seedIndex], seedIndex);
      addedAny = true;
    }

    deepCursor += 1;
  }

  if (crawlEntries.length === 0) {
    outputItems.push({
      json: {
        ...row,
        targetUrl: '',
        targetHost: '',
        targetIsSocial: false,
        seed_url: '',
        seed_source: 'none',
        crawl_depth: 0,
        url_source: 'none',
        url_detected: false,
        source_row_index: sourceIndex,
        source_row_number: row.row_number ?? '',
        source_url_rank: 1,
        source_urls_count: 0,
      },
      pairedItem: { item: sourceIndex },
    });
  } else {
    outputItems.push(...crawlEntries);
  }
  } catch (err) {
    outputItems.push({
      json: {
        ...(item.json || {}),
        targetUrl: '',
        targetHost: '',
        targetIsSocial: false,
        seed_url: '',
        seed_source: 'select-url-error',
        crawl_depth: 0,
        url_source: 'error',
        url_detected: false,
        source_row_index: sourceIndex,
        source_row_number: (item.json && item.json.row_number) ?? '',
        source_url_rank: 1,
        source_urls_count: 0,
        select_url_error: String((err && err.message) || err),
      },
      pairedItem: { item: sourceIndex },
    });
  }
});

return outputItems;

const items = $input.all();
return items.map((item, idx) => {
  try {
    const j = item.json || {};
    const out = { ...j };
    if (out.html && typeof out.html === 'object') {
      if (typeof out.html.body === 'string') {
        out.statusCode = out.html.statusCode ?? out.statusCode ?? 0;
        out.html = out.html.body;
      } else {
        try { out.html = JSON.stringify(out.html); } catch { out.html = String(out.html); }
      }
    }
    if (typeof out.html !== 'string') out.html = out.html == null ? '' : String(out.html);
    if (!out.statusCode && j.body && typeof j.body === 'string' && !out.html) out.html = j.body;
    return { json: out, pairedItem: item.pairedItem ?? { item: idx } };
  } catch (err) {
    return { json: { ...(item.json || {}), html: '', normalize_error: String((err && err.message) || err) }, pairedItem: item.pairedItem ?? { item: idx } };
  }
});

const inputItems = $input.all();

const emailRegex = /[a-z0-9._%+-]+@[a-z0-9\-._]*[a-z0-9а-яё-]+\.(?:[a-zа-яё]{2,24}|xn--[a-z0-9-]{2,58})/giu;
const emailValidationRegex = /^[a-z0-9._%+-]+@[a-z0-9\-._]*[a-z0-9а-яё-]+\.(?:[a-zа-яё]{2,24}|xn--[a-z0-9-]{2,58})$/iu;
const mailtoRegex = /mailto:([^\s"'<>]+)/gi;

const obfuscatedEmailRegexEn =
  /([a-z0-9._%+-]+)\s*(?:\[at\]|\(at\)|\{at\}|\sat\s|\{@\}|＠)\s*([a-z0-9а-яё.-]+)\s*(?:\[dot\]|\(dot\)|\{dot\}|\sdot\s|\{\.\}|．)\s*([a-zа-яё]{2,24}|xn--[a-z0-9-]{2,58})/giu;

const obfuscatedEmailRegexRu =
  /([a-z0-9._%+-]+)\s*(?:\[собака\]|\(собака\)|\{собака\}|\sсобака\s|\[собачка\]|\(собачка\)|\sсобачка\s|\[at\]|\(at\)|\sat\s)\s*([a-z0-9а-яё.-]+)\s*(?:\[точка\]|\(точка\)|\{точка\}|\sточка\s|\[dot\]|\(dot\)|\sdot\s)\s*([a-zа-яё]{2,24}|xn--[a-z0-9-]{2,58})/giu;

const ruLabelRegex = /(?:почта|электронная\s*почта|e-?mail|пишите\s+на)\s*[:\-–]?\s*([a-z0-9._%+-]+@[a-z0-9\-._]*[a-z0-9а-яё-]+\.(?:[a-zа-яё]{2,24}|xn--[a-z0-9-]{2,58}))/giu;
const dataAttrRegex = /\bdata-(?:e-?mail|mail)\s*=\s*["']([^"']+)["']/giu;
const itempropEmailRegex = /<[^>]*\bitemprop\s*=\s*["']email["'][^>]*>([\s\S]{0,300}?)<\/[^>]+>|\bitemprop\s*=\s*["']email["'][^>]*\bcontent\s*=\s*["']([^"']+)["']/giu;
const cfEncodedRegex = /data-cfemail\s*=\s*["']([a-f0-9]{4,})["']/gi;
const cfemailHrefRegex = /\/cdn-cgi\/l\/email-protection#([a-f0-9]{4,})/gi;

const blockedLocalPatterns = [
  /^example/i,
  /^test/i,
  /^noreply/i,
  /^no-reply/i,
  /^donotreply/i,
  /^mailer-daemon$/i,
];

const decodeHtmlEntitiesLite = (text) =>
  String(text || '')
    .replace(/&amp;/gi, '&')
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/gi, "'")
    .replace(/&lt;/gi, '<')
    .replace(/&gt;/gi, '>')
    .replace(/&#x([0-9a-f]+);/gi, (_, hex) => String.fromCharCode(parseInt(hex, 16)))
    .replace(/&#(\d+);/g, (_, dec) => String.fromCharCode(parseInt(dec, 10)));

const decodeCfEmail = (hexString) => {
  try {
    if (!hexString || hexString.length < 4 || hexString.length % 2 !== 0) return '';
    const key = parseInt(hexString.slice(0, 2), 16);
    let decoded = '';
    for (let i = 2; i < hexString.length; i += 2) {
      decoded += String.fromCharCode(parseInt(hexString.slice(i, i + 2), 16) ^ key);
    }
    return decoded;
  } catch {
    return '';
  }
};

const normalizeEmail = (value) => {
  if (!value) return '';
  let email = String(value).trim();
  email = decodeHtmlEntitiesLite(email);
  email = email
    .replace(/^mailto:/i, '')
    .replace(/^['"\s<>()\[\]{}]+|['"\s<>()\[\]{}.,;:!]+$/g, '')
    .replace(/\u200b|\u200c|\u200d|\ufeff/g, '')
    .toLowerCase();

  if (!/@/.test(email) || /\s/.test(email) || email.length > 254) return '';
  if (!emailValidationRegex.test(email)) return '';
  return email;
};

const isBlocked = (email) => {
  if (!email) return true;
  const local = email.split('@')[0] || '';
  return blockedLocalPatterns.some((rx) => rx.test(local));
};

const collectByRegex = (text, regex, mapFn) => {
  const found = [];
  for (const m of String(text || '').matchAll(regex)) {
    const candidate = mapFn(m);
    if (!candidate) continue;
    const email = normalizeEmail(candidate);
    if (email && !isBlocked(email)) found.push(email);
  }
  return found;
};

const extractFromJsonLikeScripts = (html) => {
  const found = new Set();
  const scriptRegex = /<script\b[^>]*>([\s\S]*?)<\/script>/gi;

  const walk = (node) => {
    if (!node) return;
    if (typeof node === 'string') {
      const emails = node.match(emailRegex) || [];
      for (const e of emails) {
        const n = normalizeEmail(e);
        if (n && !isBlocked(n)) found.add(n);
      }
      emailRegex.lastIndex = 0;
      return;
    }
    if (Array.isArray(node)) return node.forEach(walk);
    if (typeof node === 'object') return Object.values(node).forEach(walk);
  };

  for (const m of String(html || '').matchAll(scriptRegex)) {
    const scriptBody = String(m[1] || '').trim();
    if (!scriptBody) continue;
    if (!(/__NEXT_DATA__|__INITIAL_STATE__|window\.__NUXT__|window\.__INITIAL_STATE__/i.test(scriptBody))) continue;

    let jsonText = scriptBody;
    const assignMatch = scriptBody.match(/(?:window\.)?__(?:NUXT__|INITIAL_STATE__)\s*=\s*([\s\S]*?);?\s*$/i);
    if (assignMatch && assignMatch[1]) jsonText = assignMatch[1].trim();

    try {
      walk(JSON.parse(jsonText));
      continue;
    } catch {}

    const inline = scriptBody.match(emailRegex) || [];
    for (const e of inline) {
      const n = normalizeEmail(e);
      if (n && !isBlocked(n)) found.add(n);
    }
    emailRegex.lastIndex = 0;
  }

  return Array.from(found);
};

const extractEmailsFromText = (text) => {
  const found = new Set();
  const raw = String(text || '');
  const decodedEntity = decodeHtmlEntitiesLite(raw);
  let decodedUri = decodedEntity;
  try { decodedUri = decodeURIComponent(decodedEntity); } catch {}

  const variants = [raw, decodedEntity, decodedUri];

  for (const variant of variants) {
    for (const m of variant.match(emailRegex) || []) {
      const n = normalizeEmail(m);
      if (n && !isBlocked(n)) found.add(n);
    }
    emailRegex.lastIndex = 0;

    for (const m of variant.matchAll(mailtoRegex)) {
      const n = normalizeEmail((m[1] || '').split('?')[0]);
      if (n && !isBlocked(n)) found.add(n);
    }

    for (const m of variant.matchAll(obfuscatedEmailRegexEn)) {
      const n = normalizeEmail(`${m[1] || ''}@${m[2] || ''}.${m[3] || ''}`);
      if (n && !isBlocked(n)) found.add(n);
    }

    for (const m of variant.matchAll(obfuscatedEmailRegexRu)) {
      const n = normalizeEmail(`${m[1] || ''}@${m[2] || ''}.${m[3] || ''}`);
      if (n && !isBlocked(n)) found.add(n);
    }

    for (const m of variant.matchAll(ruLabelRegex)) {
      const n = normalizeEmail(m[1] || '');
      if (n && !isBlocked(n)) found.add(n);
    }

    for (const e of collectByRegex(variant, dataAttrRegex, (m) => m[1])) found.add(e);
    for (const e of collectByRegex(variant, itempropEmailRegex, (m) => m[1] || m[2])) found.add(e);

    for (const m of variant.matchAll(cfEncodedRegex)) {
      const d = decodeCfEmail(m[1] || '');
      const n = normalizeEmail(d);
      if (n && !isBlocked(n)) found.add(n);
    }

    for (const m of variant.matchAll(cfemailHrefRegex)) {
      const d = decodeCfEmail(m[1] || '');
      const n = normalizeEmail(d);
      if (n && !isBlocked(n)) found.add(n);
    }
  }

  return Array.from(found);
};

const extractFromJsonLd = (html) => {
  const found = new Set();
  const blockRegex = /<script\b[^>]*type=["']application\/ld\+json["'][^>]*>([\s\S]*?)<\/script>/gi;

  const walk = (node) => {
    if (!node) return;
    if (typeof node === 'string') {
      const matches = node.match(emailRegex) || [];
      for (const m of matches) {
        const n = normalizeEmail(m);
        if (n && !isBlocked(n)) found.add(n);
      }
      emailRegex.lastIndex = 0;
      return;
    }
    if (Array.isArray(node)) return node.forEach(walk);
    if (typeof node === 'object') return Object.values(node).forEach(walk);
  };

  for (const match of String(html || '').matchAll(blockRegex)) {
    const jsonText = String(match[1] || '').trim();
    if (!jsonText) continue;
    try {
      walk(JSON.parse(jsonText));
    } catch {
      const inner = jsonText.match(emailRegex) || [];
      for (const e of inner) {
        const n = normalizeEmail(e);
        if (n && !isBlocked(n)) found.add(n);
      }
      emailRegex.lastIndex = 0;
    }
  }

  return Array.from(found);
};

const rankEmails = (emails, domainsHint) => {
  const hints = new Set((domainsHint || []).map((d) => String(d || '').toLowerCase().replace(/^www\./, '')).filter(Boolean));
  const preferredLocals = /^(info|contact|hello|support|sales|office|mail|admin)$/i;
  const noisyLocals = /^(noreply|no-reply|donotreply|mailer-daemon|example|test)$/i;

  const score = (email) => {
    const [local, domainRaw] = String(email || '').toLowerCase().split('@');
    const domain = (domainRaw || '').replace(/^www\./, '');
    let s = 0;

    if (hints.has(domain)) s += 120;
    for (const hint of hints) {
      if (domain.endsWith('.' + hint) || hint.endsWith('.' + domain)) { s += 100; break; }
    }
    if (preferredLocals.test(local || '')) s += 40;
    if ((local || '').length <= 4) s += 5;
    if (/\d{3,}/.test(local || '')) s -= 12;
    if (noisyLocals.test(local || '')) s -= 80;

    return s;
  };

  return Array.from(new Set(emails || []))
    .map((email) => ({ email, score: score(email) }))
    .sort((a, b) => b.score - a.score || a.email.localeCompare(b.email))
    .map((x) => x.email);
};

const getDomainHints = (bucket) => {
  const hints = new Set();
  for (const url of bucket.fetchedUrls) {
    try {
      const host = new URL(url).hostname.replace(/^www\./i, '').toLowerCase();
      if (/catalog\.api\.2gis\./i.test(host)) continue;
      hints.add(host);
    } catch {}
  }
  const targetHost = String(bucket.mergedJson.targetHost || '').toLowerCase().replace(/^www\./, '');
  if (targetHost) hints.add(targetHost);
  return Array.from(hints);
};

const maxHtmlLength = 1500000;
const buckets = new Map();

for (let idx = 0; idx < inputItems.length; idx++) {
  try {
    const item = inputItems[idx];
    const currentJson = item.json || {};
    const explicitSourceIndex = Number(currentJson.source_row_index);
    const sourceIndex = Number.isInteger(explicitSourceIndex) && explicitSourceIndex >= 0 ? explicitSourceIndex : idx;

    if (!buckets.has(sourceIndex)) {
      buckets.set(sourceIndex, {
        mergedJson: { ...currentJson },
        emailsSet: new Set(),
        fetchedUrls: new Set(),
        successUrls: new Set(),
        hasFetchError: false,
        maxStatusCode: 0,
      });
    }

    const bucket = buckets.get(sourceIndex);
    bucket.mergedJson = { ...bucket.mergedJson, ...currentJson };

    let htmlRaw = String(currentJson.html ?? currentJson.body ?? currentJson.data ?? currentJson.response ?? '');
    if (htmlRaw.length > maxHtmlLength) htmlRaw = htmlRaw.slice(0, maxHtmlLength);

    const statusCode = Number(currentJson.statusCode || currentJson.status || 0);
    if (statusCode && statusCode > bucket.maxStatusCode) bucket.maxStatusCode = statusCode;

    const prepared = htmlRaw
      .replace(/<style\b[^>]*>[\s\S]*?<\/style>/gi, ' ')
      .replace(/<!--([\s\S]*?)-->/g, ' ');

    for (const e of extractEmailsFromText(prepared)) bucket.emailsSet.add(e);
    for (const e of extractFromJsonLd(htmlRaw)) bucket.emailsSet.add(e);
    for (const e of extractFromJsonLikeScripts(htmlRaw)) bucket.emailsSet.add(e);

    const fetchedUrl = String(currentJson.targetUrl || '').trim();
    if (fetchedUrl) {
      bucket.fetchedUrls.add(fetchedUrl);
      const isSuccess = htmlRaw.length > 0 && (!statusCode || statusCode < 400);
      if (isSuccess) bucket.successUrls.add(fetchedUrl);
    }

    if (currentJson.error || (statusCode && statusCode >= 400) || (!htmlRaw && fetchedUrl)) {
      bucket.hasFetchError = true;
    }
  } catch (err) {
    const fallbackJson = (inputItems[idx] && inputItems[idx].json) || {};
    const fallbackKey = Number.isInteger(Number(fallbackJson.source_row_index)) ? Number(fallbackJson.source_row_index) : idx;
    if (!buckets.has(fallbackKey)) {
      buckets.set(fallbackKey, {
        mergedJson: { ...fallbackJson },
        emailsSet: new Set(),
        fetchedUrls: new Set(),
        successUrls: new Set(),
        hasFetchError: true,
        maxStatusCode: 0,
      });
    }
    const bucket = buckets.get(fallbackKey);
    bucket.hasFetchError = true;
    bucket.mergedJson.extract_error = String((err && err.message) || err);
  }
}

const sourceIndexes = Array.from(buckets.keys()).sort((a, b) => a - b);

return sourceIndexes.map((sourceIndex) => {
  const bucket = buckets.get(sourceIndex);
  const mergedJson = { ...bucket.mergedJson };
  const newEmails = Array.from(bucket.emailsSet);

  const existing1 = String(mergedJson['E-mail'] ?? mergedJson['E-mail 1'] ?? mergedJson['Email'] ?? '').trim().toLowerCase();
  const existing2 = String(mergedJson['E-mail 2'] ?? mergedJson['Email 2'] ?? '').trim().toLowerCase();
  const existing3 = String(mergedJson['E-mail 3'] ?? mergedJson[' E-mail 3'] ?? mergedJson['Email 3'] ?? '').trim().toLowerCase();

  const existingList = [existing1, existing2, existing3].filter(Boolean);
  const existingSet = new Set(existingList);

  const ranked = rankEmails([...existingList, ...newEmails], getDomainHints(bucket));
  const final1 = ranked[0] || '';
  const final2 = ranked[1] || '';
  const final3 = ranked[2] || '';

  const trulyNewEmails = ranked.filter((e) => !existingSet.has(e));

  mergedJson.source_row_index = sourceIndex;
  mergedJson.parsed_urls = Array.from(bucket.fetchedUrls);
  mergedJson.parsed_urls_count = mergedJson.parsed_urls.length;
  mergedJson.success_urls_count = bucket.successUrls.size;
  mergedJson.max_status_code = bucket.maxStatusCode;

  mergedJson.emails_array = ranked;
  mergedJson.emails_string = ranked.join(', ');
  mergedJson.new_emails = trulyNewEmails;
  mergedJson.new_emails_count = trulyNewEmails.length;
  mergedJson.email_1 = final1;
  mergedJson.email_2 = final2;
  mergedJson.email_3 = final3;
  mergedJson.ID = mergedJson.ID ?? '';

  if (newEmails.length > 0) {
    mergedJson.parse_status = trulyNewEmails.length > 0 ? 'emails_found' : 'emails_unchanged';
  } else if (bucket.hasFetchError && bucket.successUrls.size === 0) {
    mergedJson.parse_status = 'fetch_error';
  } else if (bucket.fetchedUrls.size === 0) {
    mergedJson.parse_status = 'no_url';
  } else {
    mergedJson.parse_status = 'no_email_found';
  }

  delete mergedJson.html;
  delete mergedJson.body;
  delete mergedJson.data;
  delete mergedJson.response;
  delete mergedJson.headers;

  return { json: mergedJson, pairedItem: { item: sourceIndex } };
});

